import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"寒冬女王的怜悯","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/通用魔法/3.自然派系/寒冬女王的怜悯.md","filePath":"4.资源分区/4.术法/魔法/通用魔法/3.自然派系/寒冬女王的怜悯.md"}'),d={name:"4.资源分区/4.术法/魔法/通用魔法/3.自然派系/寒冬女王的怜悯.md"};function _(l,a,i,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"寒冬女王的怜悯",tabindex:"-1"},[s("寒冬女王的怜悯 "),e("a",{class:"header-anchor",href:"#寒冬女王的怜悯","aria-label":'Permalink to "寒冬女王的怜悯"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新秩序008")])])],-1),o('<h1 id="寒冬女王的怜悯-1" tabindex="-1">寒冬女王的怜悯 <a class="header-anchor" href="#寒冬女王的怜悯-1" aria-label="Permalink to &quot;寒冬女王的怜悯&quot;">​</a></h1><p>寒冬女王的怜悯<br> B+4000<br> 类型：攻击技<br> 成分：动作<br> 能耗：10<br> 派系：自然<br> 动作：标准动作<br> 能够轻易改变气候的魔法，该魔法需要极长的引导时间，角色需要吟唱繁杂的魔咒构筑一个半径为智力/6米的大型魔法阵，在引导期间法阵会持续产生大量的冰元素充斥整个法阵，法阵中的温度会开始逐渐降低，当法阵成型时，法阵内的温度会降至零度，随后以每秒-10℃速度迅速降至绝对零度，该效果将一直持续直到施法者法力耗尽或主动停止引导。<br> 使用标准动作进行最后一个引导阶段时，将进行一次施法攻击，并记录出目，所有仍在法阵中的人（无论敌我）都需进行一次强韧豁免对抗出目，承受等同于二者差值的伤害，并再进行一次标准强韧豁免对抗等同于出目的冻结点数。<br> 施法者可以提前设置施法锚点从而节省引导时间，锚点为法阵直径正圆形五芒星五点，每设置成功一个锚点施法者引导时间会缩短一个标准动作的时间，当5个锚点全部设定完毕后施法时间将缩减至一个标准动作引导，只有当引导至绝对零度时才会完全生效，此前并不会有实际效力。当法阵引导完成后，使用者可以每轮消耗一个标准动作和对应的能耗继续维持这个法阵，在法阵之中的所有人还会继续受到法阵的攻击。<br> 表现力：在引导期间法阵中的温度会开始逐渐降低，环境会缓慢变成冬季甚至可能出现降雪，当引导完毕后随着巨大的蓝色法阵隐射于地面，所有位于法阵中的生物都会听到一名女性的叹息声随后法阵内的温度会急速降低之至绝对零度，位于法阵中的任何事物都会被极速冻结崩碎，该效果影响高度为智力/3米。<br> 备注：每个锚点设定需要施法者使用一个标准动作引导布置法阵且需要施法者额外消耗10点能量（仍可被自然派系减少），施法者能够感知锚点是否已被摧毁。<br> 备注2：当禁咒成功释放后，温度最低降至零下270度总用时27秒。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",_]]);export{f as __pageData,m as default};
